var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저쪽은 거의 마무리가 되었나 보네요.","JPN":"あちらはほぼ片づいたようですね。","ENG":"Looks like they're almost finished over there.","TWN":"那邊好像快結束了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아 참, 그러고 보니 제 선물은 마음에 드셨나요?","JPN":"そうだ、そういえば我々のプレゼントはいかがでしたか？","ENG":"Oh, right. Did you like our present?","TWN":"對了，我想起來了，你喜歡我送的禮物嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……생물학부장 말이군요.","JPN":"……生物学部長のことですか。","ENG":"You are talking about the Dean of Biology.","TWN":"……生物學院院長嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"TWN":"……生物學院院長嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 레지나 님의 다리를 부러뜨리다니, 너무하지 않나요.","JPN":"はい。レジーナ様の足を折るなんて、酷すぎますよね？","ENG":"Yes. It was rude of him to break your leg.","TWN":"是的，他居然敢打斷蕾佳娜的腿，太過分了不是嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 직접 처리하시는 편이 만족스러우실 것 같아, 적당한 이유로 보내 드렸답니다.","JPN":"それでも直接処理した方がご満足いただけると思って、適当な理由で送りました。","ENG":"We believed it would be more satisfying if you took care of him yourself, so we sent him there with a compelling reason.","TWN":"不過我們覺得你會更喜歡親自解決他，所以就找了個適當的理由派他過去。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러면…… 어떻게 할까요, 레지나 님.","JPN":"それでは……どういたしましょう、レジーナ様。","ENG":"Then... What shall we do next, Miss Regina?","TWN":"那麼……你要怎麼做呢，蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"지금이라도 분열된 파편들을 회수하세요, 에델.","JPN":"今からでも分裂した破片を回収しなさい、エデル。","ENG":"Retrieve the broken Fragments now, Edel.","TWN":"現在也不遲，請收回分裂的碎片，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그리고 순순히 제 것이 되세요. 타협은 없습니다.","JPN":"それから、素直に私のものになりなさい。妥協はありません。","ENG":"And submit yourself to my control. This is not negotiable.","TWN":"然後，乖乖地成為我的所有物，我不會妥協的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"TWN":"然後，乖乖地成為我的所有物，我不會妥協的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이미 너무 많은 피를 흘렸어요.","JPN":"すでにあまりにも多くの血が流れました。","ENG":"Enough blood has spilled already.","TWN":"已經有太多人流血犧牲了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"충분한 대가를 마련하지 않으면 합중국부터 가만히 있지 않을 겁니다.","JPN":"十分な対価を用意しないかぎり、合衆国からして黙ってはいないはずですわ。","ENG":"The States will not stand by unless the price is paid.","TWN":"如果不付出足夠的代價，合眾國也不會善罷甘休。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"대개의 사정은 꿰뚫고 계시네요.","JPN":"大概の事情は見抜いておられますね。","ENG":"You seem to know the situation better than us.","TWN":"大致情況你都看透了呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 이건 어떨까요?","JPN":"なら、これはどうでしょう？","ENG":"Then how about this?","TWN":"那這樣如何？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이 세계에는 신이 세운 법칙이 존재한답니다.","JPN":"この世界には神が立てた法則が存在します。","ENG":"In this world, there is a rule created by god.","TWN":"這個世界上存在神確立的法則。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"가령 클리포트 게임의 경우……","JPN":"例えば、クリフォトゲームの場合……","ENG":"For example, in the case of Qliphoth Game...","TWN":"假如逆卡巴拉遊戲……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전체적으로 침공 받는 세계에 유리한 대신, 마왕에게도 그에 걸맞은 보상이 주어지죠.","JPN":"全体的に、侵攻される世界に有利である代わりに、魔王にもそれ相応の報酬が与えられます。","ENG":"Overall, the world getting invaded is advantageous, but the Demon Lord is also rewarded appropriately.","TWN":"從整體上講對被入侵的世界有利，而魔王也會得到相應的回報。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 가끔 느꼈지만 당신은 이상한 부분에서 이해력이 부족해요.","JPN":"エデル、たまに感じてはいましたが、あなたは変なところで理解力が足りませんわ。","ENG":"Edel, I have noticed that you occasionally lack understanding in the most unexpected places.","TWN":"艾瑟兒，偶爾我會感覺到，你在奇怪的地方缺乏理解能力。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래요? 저희가 레지나 님의 행동 양식에 대해 잘못 이해한 게 있을까요?","JPN":"そうですか？　我々がレジーナ様の行動様式について勘違いしていることがあると？","ENG":"Really? Are you saying that we haven't fully understood your mannerisms?","TWN":"是嗎？我們對蕾佳娜的行為模式有什麼誤解嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"네. 처음부터 끝까지, 전부.","JPN":"はい。最初から最後まで、全部。","ENG":"Yes. From start to finish, all of it.","TWN":"是的，從頭到尾，全部。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 영웅 따위가 되겠다고 나선 적 없습니다.","JPN":"私は英雄なんかになると宣言したことはありません。","ENG":"I never volunteered to be some hero.","TWN":"我從來沒有因為要當英雄而站出來過。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이건 전부 지극히 개인적인 목적을 위해서예요.","JPN":"これはすべて、ごく個人的な目的のためです。","ENG":"This is entirely for personal reasons.","TWN":"這些全都是為了私人的目的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 모든 학문은 천 번의 강의보다 한 번의 실습이 더 와 닿기 마련이죠.","JPN":"ですが、すべての学問は千回の講義より一度の実習の方が理解できるもの。","ENG":"However, as with all studies, one practice session is worth a thousand lectures.","TWN":"但是所有學問都是，比起一千堂課，一次實踐肯定會更深入人心。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그 사실을, 지금부터 당신의 몸에 새겨 드리겠습니다.","JPN":"その事実を、今からあなたの体に刻み込んでさしあげます。","ENG":"Please keep that closely in mind from now on.","TWN":"這個事實，從現在起我就要刻到你身上。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"TWN":"這個事實，從現在起我就要刻到你身上。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};